B.I2=new A.ar("METAR LTBA 120850Z 35015KT 9999 FEW030 SCT100 18/08 Q1013 NOSIG","\u0130stanbul Atat\xfcrk, 12. g\xfcn 08:50 UTC, r\xfczgar 350\xb0/15 knot, g\xf6r\xfc\u015f >10km, 3000ft AGL az bulut, 18\xb0C, Q1013, de\u011fi\u015fiklik yok.","NOSIG")
