B.O1=s(["turn off","confirm","cross-check","identify"],t.s)
B.ZB=new A.a1(-231,B.as,781,"Before performing any engine shutdown action, the crew should \u2026\u2026\u2026\u2026 the affected engine.",B.O1,2,B.z,null,null,null)
B.RG=s(["activate","fire","discharge","release"],t.s)
