B.Tw=s(["stall","surge","failure","seizure"],t.s)
B.Yz=new A.a1(-233,B.as,783,"A compressor stall in a jet engine is also known as a compressor \u2026\u2026\u2026\u2026.",B.Tw,1,B.aH,null,null,null)
