B.Ln=new A.K(B.W,"Formal aviation documents have specific language patterns","Operations manuals, maintenance manuals (AMM), and airworthiness directives use formal English with precise legal and technical implications. Translation questions at this level require understanding not just the words, but the **regulatory intent** behind them.",null,null,null)
B.Mw=new A.K(B.A,"\ud83d\udcd5 Regulatory Language","**Shall** \u2014 mandatory requirement (legal obligation in ICAO documents)\n**Should** \u2014 recommended practice (not legally binding, but expected)\n**May** \u2014 permitted (optional)\n**Must** \u2014 mandatory (operational context, not formal ICAO legal text)\n\n**Compliance** \u2014 acting in accordance with a regulation\n**In accordance with (IAW)** \u2014 following specified requirements\n**Subject to** \u2014 conditional upon something\n**Notwithstanding** \u2014 despite; even though\n**Hereinafter** \u2014 from this point forward in the document",null,null,null)
B.Ha=new A.ar("All maintenance shall be carried out by qualified personnel in accordance with the approved data.","T\xfcm bak\u0131m i\u015flemleri, onayl\u0131 veriye uygun olarak nitelikli personel taraf\u0131ndan yap\u0131lmal\u0131d\u0131r.","shall be carried out")
B.H1=new A.ar("Subject to operational requirements, the interval may be extended by not more than 10 flight hours.","Operasyonel gerekliliklere ba\u011fl\u0131 olarak, interval en fazla 10 u\xe7u\u015f saati uzat\u0131labilir.","Subject to")
B.H5=new A.ar("Notwithstanding the above, the captain retains full authority over the safe conduct of the flight.","Yukar\u0131dakilerle birlikte, kaptan u\xe7u\u015fun g\xfcvenli y\xfcr\xfct\xfclmesi konusunda tam yetkisini korur.","Notwithstanding")
B.QR=s([B.Ha,B.H1,B.H5],t.l)
B.Nj=new A.K(B.X,"Manual Language Examples",null,B.QR,null,null)
B.Lw=new A.K(B.Y,"\u2708\ufe0f Translation Tips",'Critical translation distinctions:\n\u2022 "**shall**" in ICAO docs \u2260 "will" (future) \u2014 it means **mandatory**\n\u2022 "**notwithstanding**" \u2260 "noting" \u2014 it means **despite** or **regardless of**\n\u2022 "**in the event of**" = "e\u011fer \u2026 olursa/durumunda" (conditional)\n\u2022 "**prior to**" = "\u2026dan \xf6nce" (before) \u2014 formal version of "before"\n\u2022 "**subsequent to**" = "\u2026dan sonra" (after) \u2014 formal version of "after"',null,null,null)
B.P7=s(["Will possibly complete","Are encouraged to complete","Must complete (mandatory)","Should ideally complete"],t.s)
