B.Nb=new A.K(B.W,"Advanced vocabulary separates good from excellent","ICAO Level 5 and 6 proficiency requires mastery of low-frequency but high-stakes technical vocabulary. This lesson covers the terms that distinguish advanced candidates and that frequently appear in the hardest exam questions.",null,null,null)
B.Mx=new A.K(B.A,"\ud83c\udfc6 Advanced Operational Terms","**EDTO/ETOPS** \u2014 Extended Diversion Time Operations (flying far from alternate airports)\n**RVSM** \u2014 Reduced Vertical Separation Minima (300m / 1,000ft between FL290\u2013FL410)\n**PBN** \u2014 Performance-Based Navigation (RNP, RNAV specs)\n**MNPS** \u2014 Minimum Navigation Performance Specification (oceanic)\n**MEL** \u2014 Minimum Equipment List (approved deferred defects)\n**CDL** \u2014 Configuration Deviation List (approved structural deviations)\n**AOG** \u2014 Aircraft on Ground (urgent unserviceable aircraft)",null,null,null)
B.KZ=new A.K(B.A,"\u26a0\ufe0f Safety-Critical Vocabulary","**Controlled flight into terrain (CFIT)** \u2014 aircraft in controlled flight strikes terrain\n**Loss of control in-flight (LOC-I)** \u2014 most fatal accident category\n**Runway incursion** \u2014 unauthorized presence on runway\n**Airspace infringement** \u2014 entering controlled airspace without clearance\n**Human factors** \u2014 study of human performance in aviation systems\n**Crew Resource Management (CRM)** \u2014 effective use of all resources\n**Threat and Error Management (TEM)** \u2014 proactive safety model",null,null,null)
B.HF=new A.ar("The accident was classified as CFIT \u2014 the crew was unaware of the proximity to terrain.","Kaza, CFIT olarak s\u0131n\u0131fland\u0131r\u0131ld\u0131 \u2014 ekip, araziye olan yak\u0131nl\u0131\u011f\u0131ndan habersizdi.","CFIT")
B.HA=new A.ar("Under RVSM, vertical separation between FL290 and FL410 is reduced to 1,000 feet.","RVSM kapsam\u0131nda, FL290 ile FL410 aras\u0131ndaki dikey ay\u0131rma 1.000 fite indirilmi\u015ftir.","RVSM")
B.Hd=new A.ar("The aircraft was dispatched on the MEL, with one hydraulic pump deferred.","U\xe7ak, bir hidrolik pompa ertelenmi\u015f olarak MEL'e g\xf6re hava arac\u0131 olarak g\xf6nderildi.","MEL")
B.Rq=s([B.HF,B.HA,B.Hd],t.l)
B.KU=new A.K(B.X,"Expert Vocabulary in Context",null,B.Rq,null,null)
B.Nu=new A.K(B.Y,"\u2708\ufe0f Exam Strategy","For advanced vocabulary questions:\n\u2022 **EDTO/ETOPS** = about how far from alternates you can fly (oceanic/remote operations)\n\u2022 **MEL** = what you CAN fly with broken; **CDL** = approved structural missing parts\n\u2022 **PBN** includes both **RNAV** and **RNP** (RNP has on-board monitoring + alerting)\n\u2022 **Runway incursion** vs. **airspace infringement** \u2014 both are serious safety events but involve different areas\n\u2022 **CRM** is about **using available resources** \u2014 not just communication",null,null,null)
