B.MG=new A.K(B.W,"ADs are mandatory safety compliance documents","An Airworthiness Directive (AD) is a legally binding document issued by a civil aviation authority requiring specific action to correct an unsafe condition in an aircraft type. Non-compliance is illegal and grounds for operating certificate suspension.\n\nAD language is the most precise regulatory language in aviation \u2014 every word has legal weight.",null,null,null)
B.Mj=new A.K(B.A,"\ud83d\udcdc AD Structure",'A typical AD contains:\n1. **Applicability** \u2014 which aircraft/engines/parts are affected\n2. **Unsafe condition** \u2014 the hazard being addressed\n3. **Required action** \u2014 what must be done\n4. **Compliance time** \u2014 when it must be done (e.g., "within 50 flight hours")\n5. **Method** \u2014 how to comply (service bulletin, specific procedure)\n6. **Alternative Method of Compliance (AMOC)** \u2014 approved alternative\n7. **Costs** \u2014 estimated compliance cost',null,null,null)
B.KN=new A.K(B.A,"\u26a0\ufe0f Compliance Time Language",'**"Within 50 flight hours after the effective date"** \u2014 must be done before 50 more hours\n**"At the next scheduled maintenance"** \u2014 at next A/B/C check\n**"Before further flight"** \u2014 aircraft must not fly until complied with\n**"At first opportunity"** \u2014 as soon as practical (not as urgent as "before further flight")\n**"Repetitive inspection every 200 FH"** \u2014 not a one-time action; must be repeated\n**"Terminating action"** \u2014 permanently satisfies the AD (no more repetitive checks needed)',null,null,null)
B.GR=new A.ar("This AD requires repetitive inspections of the fuselage skin every 500 flight cycles.","Bu AD, her 500 u\xe7u\u015f \xe7evriminde g\xf6vde kaplamas\u0131n\u0131n tekrarl\u0131 denetimlerini gerektirmektedir.","repetitive inspections")
B.HH=new A.ar("The applicability of this AD extends to all Boeing 737-800 aircraft with serial numbers 35201 through 41234.","Bu AD'nin uygulanabilirli\u011fi, 35201 ile 41234 aras\u0131ndaki seri numaralar\u0131na sahip t\xfcm Boeing 737-800 u\xe7aklar\u0131n\u0131 kapsamaktad\u0131r.","applicability")
B.GT=new A.ar("Compliance is required before further flight after the effective date.","Y\xfcr\xfcrl\xfck tarihinden sonra daha fazla u\xe7u\u015ftan \xf6nce uyum zorunludur.","before further flight")
B.TQ=s([B.GR,B.HH,B.GT],t.l)
B.LO=new A.K(B.X,"AD Language Examples",null,B.TQ,null,null)
B.KQ=new A.K(B.Y,"\u2708\ufe0f Advanced Reading Strategy",'For AD reading questions:\n\u2022 **Applicability** section tells you which aircraft are affected \u2014 check this first\n\u2022 "**Before further flight**" = the most urgent compliance time \u2014 aircraft is GROUNDED\n\u2022 "**Terminating action**" = once done, no more repetitive inspections needed\n\u2022 **AMOC** = alternative compliance method \u2014 must be approved by the authority\n\u2022 "**At the next scheduled**" does NOT mean "optional" \u2014 it is mandatory at that point\n\u2022 Read dates carefully \u2014 "after the effective date" vs. "from the date of manufacture"',null,null,null)
