B.a_Q=new A.I("Operational Meaning Interpretation","Accurately interpreting the intent of ATC instructions and translating concepts between English and your working language prevents dangerous misunderstandings.")
B.a_D=new A.I("Readback & Clearance Precision","Translation errors in clearance readbacks are a leading cause of runway incursions. Practice precision in both directions without paraphrasing critical values.")
B.a0J=new A.I("Context-Based Language Transfer","Focus on understanding aviation texts in context rather than word-for-word translation. ICAO language is formulaic \u2014 learn the patterns.")
B.a_O=new A.I("Safety Communication Accuracy","Translating safety instructions accurately ensures passenger compliance. Focus on official ICAO safety terminology rather than free translation.")
B.VV=new A.bu(B.lW,[B.a_Q,B.a_D,B.a0J,B.a_O],t.dM)
